IOT_QUESTIONS_PART8 = [{'question': 'What are the key security considerations when selecting a cloud IoT platform such as AWS IoT Core Azure IoT Hub or Google Cloud IoT?', 'options': [{'text': 'Cost is the only significant factor when selecting a cloud IoT platform as all major platforms have identical security capabilities', 'explanation': 'Cloud IoT platforms have different security capabilities, certification levels, data residency options, and compliance support. Security requirements must be assessed alongside cost in platform selection.', 'correct': False}, {'text': 'Security certifications data residency device authentication capabilities encryption standards audit logging and incident response support all require evaluation during platform selection', 'explanation': 'Correct. Cloud IoT platform security evaluation: security certifications (ISO 27001, SOC 2, PCI DSS), data residency options for regulatory compliance, device authentication support (X.509 certificates, mTLS), encryption in transit and at rest standards, audit logging and monitoring capabilities, DDoS protection for device fleets, incident response procedures and SLAs, and regulatory compliance support for your specific sector.', 'correct': True}, {'text': 'All major cloud IoT platforms have identical security capabilities making security evaluation unnecessary', 'explanation': 'Cloud IoT platforms differ significantly in security capabilities, compliance certifications, data residency options, and device management features. Security evaluation is essential before platform selection.', 'correct': False}, {'text': 'Cloud IoT platforms eliminate all security responsibilities for the deploying organisation through their managed security services', 'explanation': 'Cloud IoT platforms operate on a shared responsibility model. The platform provider secures the cloud infrastructure while the organisation is responsible for device security, access management, data classification, and application security.', 'correct': False}], 'overall_explanation': 'Cloud IoT platform shared responsibility model: provider responsible for physical infrastructure, network security, hypervisor security, and platform availability. Organisation responsible for device credentials and certificates, IoT data classification and access controls, application security built on the platform, regulatory compliance for data processed, and monitoring configuration for their IoT workloads.', 'domain': 'IoT Security - Cloud and Platform'}, {'question': 'What is the IoT cloud shared responsibility model and how does it differ from the shared responsibility model for traditional cloud computing?', 'options': [{'text': 'The IoT shared responsibility model is identical to traditional cloud shared responsibility with no additional considerations', 'explanation': 'IoT shared responsibility extends beyond traditional cloud to include device-level security responsibilities that do not exist in traditional cloud computing where the customer controls only applications and data.', 'correct': False}, {'text': 'IoT shared responsibility extends to device-level security including firmware update management device credential lifecycle physical device security and device monitoring which are customer responsibilities not covered in traditional cloud models', 'explanation': 'Correct. Traditional cloud shared responsibility: provider manages infrastructure, customer manages OS and above. IoT adds customer responsibilities: device firmware security and update management, device credential provisioning and rotation, physical device security, device network connectivity security, and monitoring of device behaviour. The cloud provider does not manage these device-level responsibilities.', 'correct': True}, {'text': 'In the IoT shared responsibility model the cloud provider is responsible for all security including device firmware and physical device security', 'explanation': 'Cloud providers manage cloud infrastructure not physical IoT devices deployed at customer premises or in the field. Device-level security including firmware and physical security are always customer responsibilities.', 'correct': False}, {'text': 'The shared responsibility model does not apply to IoT because IoT devices are not cloud computing resources', 'explanation': 'The shared responsibility model applies to IoT cloud platforms. Cloud providers manage their infrastructure while customers manage device security and the configuration of cloud IoT services they consume.', 'correct': False}], 'overall_explanation': 'IoT shared responsibility boundaries: cloud provider secures the platform infrastructure, APIs, and managed services. Customer secures device firmware and software, device credentials and certificates, physical device security, IoT data in transit from device to cloud, access controls for cloud IoT management, and monitoring configuration. Misunderstanding this boundary leads to security gaps.', 'domain': 'IoT Security - Cloud and Platform'}, {'question': 'What is the security risk of storing IoT device credentials such as API keys or certificates in plaintext in mobile applications used to manage those devices?', 'options': [{'text': 'Storing credentials in mobile apps is secure as long as the app requires a login password to open', 'explanation': 'App-level login passwords do not protect credentials stored in plaintext in the app. An attacker who extracts the app binary or accesses the device file system can retrieve plaintext credentials regardless of the app login requirement.', 'correct': False}, {'text': 'Plaintext credentials in mobile apps can be extracted through binary analysis reverse engineering or device backup access giving attackers full IoT platform access', 'explanation': 'Correct. Mobile app binary analysis can extract hardcoded credentials using tools like APKTool, Frida, or strings extraction. Plaintext credentials in app files can be accessed through Android ADB backup or iOS iTunes backup. Extracted IoT platform credentials give attackers administrative access to the entire device fleet managed through that app.', 'correct': True}, {'text': 'Mobile app credentials are protected by app store security making extraction impossible for non-jailbroken devices', 'explanation': 'App store security does not protect credentials hardcoded in app binaries or stored in plaintext app files. Binary analysis does not require jailbreaking for static analysis and dynamic analysis is possible on rooted devices.', 'correct': False}, {'text': 'Credential extraction from mobile apps requires physical device access making the risk negligible for enterprise IoT management apps', 'explanation': 'Binary analysis of app files does not require physical device access. Downloaded APK or IPA files can be analysed offline. Additionally many attack scenarios do involve device access through theft or BYOD scenarios.', 'correct': False}], 'overall_explanation': 'Secure credential storage in IoT mobile apps: use platform secure storage (Android Keystore, iOS Keychain) not plaintext files, implement certificate pinning to prevent MITM against app-to-platform communications, obfuscate app code to increase reverse engineering difficulty, use short-lived tokens rather than permanent credentials, and test apps for credential exposure using mobile application security testing (MAST) tools.', 'domain': 'IoT Security - Cloud and Platform'}, {'question': 'An IoT cloud platform API processes commands from mobile apps to IoT devices. What API security controls are essential to prevent unauthorised device control?', 'options': [{'text': 'API security for IoT only requires HTTPS encryption as unencrypted APIs are the primary risk', 'explanation': 'HTTPS encryption is necessary but insufficient. Authentication, authorisation, rate limiting, input validation, and monitoring are all essential IoT API security controls beyond encryption.', 'correct': False}, {'text': 'Authentication per request authorisation verifying the requester owns the target device rate limiting input validation and audit logging are all essential IoT API security controls', 'explanation': 'Correct. IoT command API security requirements: authentication on every request (not just session start), object-level authorisation verifying the requester owns or has permission to control the specific device, rate limiting preventing automated attack attempts, input validation rejecting malformed commands, audit logging of all command attempts including failed ones, and anomalous command pattern detection alerting on unusual command sequences.', 'correct': True}, {'text': 'API security for IoT command platforms requires only authentication with no need for per-device authorisation checks', 'explanation': 'Authentication verifies who is making the request. Authorisation verifies they have permission to control the specific device requested. Without per-device authorisation any authenticated user could control any device on the platform.', 'correct': False}, {'text': 'IoT APIs should be designed without authentication to allow emergency device control when credentials are unavailable', 'explanation': 'Unauthenticated emergency access is a critical vulnerability. Emergency access procedures should use break-glass credentials with enhanced logging not absent authentication. Authentication must always be required for IoT command APIs.', 'correct': False}], 'overall_explanation': 'IoT command API security architecture: OAuth 2.0 with short-lived access tokens, resource server validation checking token scope matches requested device and command, rate limiting per user and per device, command validation against allowed command schema, immutable audit log of all commands, anomaly detection for unusual command volumes or patterns, and separate elevated authentication for destructive commands like factory reset.', 'domain': 'IoT Security - Cloud and Platform'}, {'question': 'What is the security significance of IoT device shadow or device twin features in cloud IoT platforms?', 'options': [{'text': 'Device shadow features have no security significance as they only store non-sensitive status information', 'explanation': 'Device shadows store configuration, state, and desired settings that can include sensitive operational parameters. Unauthorised modification of device shadows can cause devices to change behaviour without direct device commands.', 'correct': False}, {'text': 'Device shadows store desired state that is pushed to devices meaning unauthorised shadow modification can change device behaviour without direct device communication and must be protected with strict access controls', 'explanation': 'Correct. Cloud IoT device shadows synchronise desired configuration to physical devices. Unauthorised modification of a device shadow can cause the physical device to change its behaviour when it next synchronises. This creates an indirect command injection vector. Shadow access must be restricted to authorised users with the same controls as direct device commands.', 'correct': True}, {'text': 'Device shadows are only readable by the device itself and cannot be accessed by cloud management systems or users', 'explanation': 'Device shadows are accessible to both the physical device and authorised cloud management systems and users. This accessibility is their purpose but also creates the need for strict access control.', 'correct': False}, {'text': 'Device shadow modifications are always visible to device operators making them safe from malicious modification', 'explanation': 'Shadow modifications may not be immediately visible to operators especially in large fleets. Monitoring shadow modifications for anomalous changes is an important security control not an inherent capability.', 'correct': False}], 'overall_explanation': 'Device shadow security: implement same access controls for shadow modification as direct device commands, audit log all shadow modifications with user attribution, alert on shadow modifications outside normal operational hours or patterns, implement shadow modification approval workflow for safety-critical parameters, and regularly audit shadow states against expected device configurations to detect unauthorised modifications.', 'domain': 'IoT Security - Cloud and Platform'}, {'question': 'What is the risk of using a single cloud IoT platform for all IoT devices across an organisation and how can resilience be improved?', 'options': [{'text': 'Using a single cloud IoT platform provides maximum security through centralised management with no resilience risks', 'explanation': 'A single platform creates a single point of failure and a high-value attack target. Platform outages, security incidents, or vendor issues can affect all IoT devices simultaneously.', 'correct': False}, {'text': 'A single platform creates a single point of failure and a high-value attack target where platform compromise affects all devices simultaneously requiring resilience through redundancy offline capability and incident response planning', 'explanation': 'Correct. Single platform risks: platform outage stops all IoT management and monitoring, platform security incident may compromise all device credentials, vendor lock-in prevents migration if platform becomes inadequate, and regulatory changes may require data residency changes affecting all devices simultaneously. Resilience: offline device operation capability, regular credential backup, incident response plan for platform compromise, and consider multi-platform architecture for critical deployments.', 'correct': True}, {'text': 'Using multiple cloud IoT platforms eliminates all security risks associated with IoT cloud management', 'explanation': 'Multi-platform architecture introduces its own complexity and security challenges including managing credentials across platforms and ensuring consistent security policies. It reduces single points of failure but does not eliminate all risks.', 'correct': False}, {'text': 'Cloud platform resilience is entirely the provider responsibility and deploying organisations have no resilience obligations', 'explanation': 'Platform providers ensure infrastructure resilience but organisations must plan for platform-level incidents affecting their IoT deployments. Business continuity planning for IoT cloud platform outages is an organisational responsibility.', 'correct': False}], 'overall_explanation': 'IoT cloud platform resilience planning: document what IoT functions are unavailable during platform outage, implement device offline operation capability for critical functions, regularly export device registry and credentials for disaster recovery, test platform outage response procedures, evaluate multi-region deployment for high-availability requirements, and maintain vendor relationship with defined SLAs and breach notification obligations.', 'domain': 'IoT Security - Cloud and Platform'}, {'question': 'What is the purpose of IoT device groups and policies in cloud platforms and what security controls should govern them?', 'options': [{'text': 'IoT device groups are only used for organisational purposes and have no security relevance', 'explanation': 'Device groups and policies directly control what IoT devices can do including which topics they can publish to, which commands they can receive, and what cloud resources they can access. Group policy management is a critical security control.', 'correct': False}, {'text': 'Device groups and policies define what each device can access and do requiring least privilege policies change management for policy modifications and audit logging of all policy changes', 'explanation': 'Correct. IoT device group policies implement least privilege at scale: devices only have permissions required for their function, policy changes follow change management processes, all policy modifications are logged and reviewed, overly permissive policies are detected through regular access reviews, and new device types undergo security review before policy assignment. Policy misconfiguration can give devices excessive access or prevent legitimate operation.', 'correct': True}, {'text': 'All IoT devices should be in a single group with full permissions to simplify management and prevent operational issues', 'explanation': 'A single group with full permissions violates least privilege and means any compromised device has access to all platform resources. Granular group policies limiting each device type to required permissions are essential.', 'correct': False}, {'text': 'Device group policies are automatically managed by cloud platforms requiring no security governance from deploying organisations', 'explanation': 'Cloud platforms provide group policy infrastructure but organisations must define, implement, and govern their own policies. Automatic policy management would require understanding operational requirements that only the deploying organisation has.', 'correct': False}], 'overall_explanation': 'IoT device policy least privilege: define minimum required permissions for each device type, implement separate policies for different device functions, review policies quarterly removing accumulated unnecessary permissions, test policy changes in non-production before applying to production fleet, alert on policy changes outside change management process, and immediately review policies when device functions change.', 'domain': 'IoT Security - Cloud and Platform'}, {'question': 'What monitoring and alerting capabilities should be implemented in a cloud IoT platform to detect security incidents?', 'options': [{'text': 'Cloud IoT platforms provide automatic security incident detection requiring no additional monitoring configuration from deploying organisations', 'explanation': 'Cloud platforms provide monitoring infrastructure but organisations must configure appropriate alerts, thresholds, and response procedures. Default platform monitoring does not automatically detect all IoT security incidents relevant to a specific deployment.', 'correct': False}, {'text': 'Device authentication failures unusual command patterns new device registrations data volume anomalies and management API access from unexpected sources all require specific monitoring and alerting', 'explanation': 'Correct. IoT cloud monitoring essentials: authentication failure rates per device alerting on brute force patterns, command volume anomalies detecting unusual automated command sequences, new device registration outside normal provisioning windows, data ingestion volume anomalies indicating potential exfiltration or attack, management API access from unexpected IPs or at unusual times, certificate expiry tracking preventing connectivity failures, and shadow modification anomalies detecting unauthorised configuration changes.', 'correct': True}, {'text': 'Only authentication failures need to be monitored as all other IoT security events are handled by platform security features', 'explanation': 'Authentication failures are one important IoT security indicator among many. Command anomalies, data volume anomalies, and management access patterns all provide valuable security signals that must be specifically monitored.', 'correct': False}, {'text': 'IoT cloud monitoring is only necessary for deployments with more than 10000 devices', 'explanation': 'IoT security monitoring is necessary for deployments of any size. Even small IoT deployments can be compromised and the absence of monitoring means incidents go undetected regardless of fleet size.', 'correct': False}], 'overall_explanation': 'IoT cloud security monitoring implementation: integrate platform logs with SIEM, define baseline metrics for normal device behaviour, configure threshold alerts for authentication failure rates, implement anomaly detection for data volume changes, monitor certificate expiry across the fleet, set up alerting for management API access patterns, and establish escalation procedures for high-severity IoT security alerts.', 'domain': 'IoT Security - Cloud and Platform'}, {'question': 'What is the security risk of IoT devices that continue operating indefinitely without reconnecting to their cloud management platform?', 'options': [{'text': 'Devices that operate without cloud connectivity are more secure because they cannot receive malicious cloud commands', 'explanation': 'While offline operation limits some attack vectors it also prevents security updates, certificate renewal, policy updates, and monitoring. The security benefits of offline operation are generally outweighed by the loss of security management capabilities.', 'correct': False}, {'text': 'Long-term offline IoT devices miss security updates certificate renewals policy changes and monitoring creating security drift where device security posture degrades over time', 'explanation': 'Correct. IoT devices that operate long-term without cloud connectivity: miss firmware security updates accumulating known vulnerabilities, cannot renew certificates leading to eventual authentication failure, miss policy updates that may address security issues, are invisible to monitoring missing compromise indicators, and may retain outdated configuration that is no longer secure. Security drift compounds over time making long-offline devices increasingly vulnerable.', 'correct': True}, {'text': 'IoT devices are designed to operate indefinitely without cloud connectivity with no security implications', 'explanation': 'Indefinite offline operation creates serious security implications including missed security updates, certificate expiry, and monitoring gaps. Well-designed IoT systems balance offline operational capability with regular connectivity for security management.', 'correct': False}, {'text': 'Long-term offline IoT devices automatically install security updates when they reconnect eliminating the security drift risk', 'explanation': 'Automatic update installation on reconnection is not a universal IoT platform feature and even where available requires the device to actually reconnect. Security drift during the offline period is a real risk regardless of reconnection behaviour.', 'correct': False}], 'overall_explanation': 'Managing IoT devices with limited connectivity: implement scheduled connectivity windows for security management even if operational data is buffered, monitor time-since-last-connection alerting on devices that have not connected within defined thresholds, prioritise security updates on first reconnection, track certificate expiry relative to device connectivity patterns, and develop procedures for recovering devices that have been offline long enough for certificates to expire.', 'domain': 'IoT Security - Cloud and Platform'}, {'question': 'What is the security consideration when decommissioning an IoT cloud platform deployment and migrating to a new provider?', 'options': [{'text': 'Platform migration has no security considerations as device credentials simply transfer to the new platform automatically', 'explanation': 'Credentials do not automatically transfer between platforms. Migration requires careful credential management, data migration with appropriate security controls, and validation that all devices are properly re-provisioned on the new platform before the old platform is decommissioned.', 'correct': False}, {'text': 'Migration requires revoking all credentials on the old platform migrating and validating data securely re-provisioning devices with new platform credentials and verifying no residual access remains on the decommissioned platform', 'explanation': 'Correct. IoT platform migration security: revoke all device credentials on the old platform after migration to prevent parallel access, migrate historical data securely with encryption and access controls, re-provision all devices with new platform credentials through secure provisioning process, validate device connectivity on new platform before old platform decommissioning, audit old platform for any remaining active credentials or data, and obtain data deletion confirmation from the old provider.', 'correct': True}, {'text': 'Platform migration should be completed as quickly as possible without security validation to minimise downtime', 'explanation': 'Speed should not compromise security validation during platform migration. Parallel operation periods require careful access management and validation must confirm complete credential revocation and data removal from the old platform.', 'correct': False}, {'text': 'The old platform provider is responsible for securely deleting all customer data after contract termination requiring no action from the deploying organisation', 'explanation': 'While providers have contractual data deletion obligations organisations must verify deletion has occurred and cannot rely solely on provider promises. Data migration validation and deletion confirmation are organisation responsibilities.', 'correct': False}], 'overall_explanation': 'IoT platform migration security checklist: data inventory (what data exists on old platform), migration plan (encryption during transfer, access controls on migration data), parallel operation security (prevent duplicate device identity on both platforms), credential revocation (audit confirming no active credentials remain on old platform), data deletion verification (written confirmation from old provider), and post-migration monitoring to confirm all devices are operational on new platform.', 'domain': 'IoT Security - Cloud and Platform'}]